{"code": "import json

# Approach: Process ETFs in batches using UNION ALL queries
# Load NYSE Arca ETF symbols
file_path = globals().get('var_functions.query_db:36', None)
if isinstance(file_path, str):
    with open(file_path, 'r') as f:
        etf_data = json.load(f)
else:
    etf_data = file_path if isinstance(file_path, list) else []

symbols = [item['Symbol'] for item in etf_data]

# Create batches - we'll generate the queries but not execute them yet
def create_batch_query(batch_symbols):
    queries = []
    for symbol in batch_symbols:
        query = f"SELECT '{symbol}' as Symbol, MAX(\"Adj Close\") as max_price FROM {symbol} WHERE Date >= '2015-01-01' AND Date <= '2015-12-31'"
        queries.append(query)
    return ' UNION ALL '.join(queries)

# Create batches of 20 symbols each (adjust size as needed)
batch_size = 20
batches = []
for i in range(0, len(symbols), batch_size):
    batch = symbols[i:i+batch_size]
    batches.append(batch)

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(symbols),
    'batches_created': len(batches),
    'batch_size': batch_size,
    'first_batch': batches[0] if batches else []
}))"}

